import{_ as s,C as n,o as i,c as p,j as e,a as r,E as t,ag as o}from"./chunks/framework.CAXxHpAX.js";const k=JSON.parse('{"title":"15. 推荐学习顺序","description":"给出从 PostgreSQL 到数据治理的阶段化学习路径，避免直接跳工具。","frontmatter":{"title":"15. 推荐学习顺序","description":"给出从 PostgreSQL 到数据治理的阶段化学习路径，避免直接跳工具。","prev":{"text":"14. 大数据方向项目实战","link":"/chapters/14-projects"},"next":{"text":"16. 能力地图","link":"/chapters/16-capability-map"}},"headers":[],"relativePath":"chapters/15-learning-order.md","filePath":"chapters/15-learning-order.md"}'),c={name:"chapters/15-learning-order.md"};function h(d,a,u,b,m,g){const l=n("Mermaid");return i(),p("div",null,[a[0]||(a[0]=e("h1",{id:"_15-推荐学习顺序",tabindex:"-1"},[r("15. 推荐学习顺序 "),e("a",{class:"header-anchor",href:"#_15-推荐学习顺序","aria-label":'Permalink to "15. 推荐学习顺序"'},"​")],-1)),a[1]||(a[1]=e("div",{class:"tip custom-block"},[e("p",{class:"custom-block-title"},"本章导读"),e("p",null,"给出从 PostgreSQL 到数据治理的阶段化学习路径，避免直接跳工具。")],-1)),t(l,{code:"flowchart%20TB%0A%20%20A%5B%22PostgreSQL%22%5D%20--%3E%20B%5B%22SQL%22%5D%0A%20%20B%20--%3E%20C%5B%22%E5%A4%A7%E8%A1%A8%E8%BE%B9%E7%95%8C%22%5D%0A%20%20C%20--%3E%20D%5B%22%E6%95%B0%E4%BB%93%22%5D%0A%20%20D%20--%3E%20E%5B%22ETL%20%2F%20CDC%22%5D%0A%20%20E%20--%3E%20F%5B%22OLAP%20%2F%20%E6%89%B9%E5%A4%84%E7%90%86%22%5D%0A%20%20F%20--%3E%20G%5B%22%E5%AE%9E%E6%97%B6%22%5D%0A%20%20G%20--%3E%20H%5B%22%E5%90%91%E9%87%8F%20%2F%20%E5%9B%BE%22%5D%0A%20%20H%20--%3E%20I%5B%22%E6%B9%96%E4%BB%93%20%2F%20%E6%B2%BB%E7%90%86%22%5D%0A"}),a[2]||(a[2]=o(`<p>学习数据系统最怕两件事。</p><h2 id="问题切入" tabindex="-1">问题切入 <a class="header-anchor" href="#问题切入" aria-label="Permalink to &quot;问题切入&quot;">​</a></h2><p>第一，直接跳工具。</p><p>第二，长期停留在单点语法。</p><p>合理顺序应该是：先建立 PostgreSQL 和 SQL 的底层直觉，再逐步进入数仓、数据链路、批流、OLAP、湖仓、向量、图和治理。</p><p>如果顺序错了，学习会出现两种典型问题：先学 Spark / Flink，却不知道数据为什么要建模、分层和治理；或者长期停留在 SQL 练习题里，不知道业务库、数仓、湖仓和 AI 数据系统如何连接。</p><h2 id="核心判断" tabindex="-1">核心判断 <a class="header-anchor" href="#核心判断" aria-label="Permalink to &quot;核心判断&quot;">​</a></h2><p>推荐顺序不是按工具流行度排列，而是按系统问题的出现顺序排列。先理解业务数据如何被组织，再理解分析查询如何表达，再理解单机边界为什么引出数仓、批流、OLAP、湖仓、向量、图和治理。</p><p>这条路线的关键是：每一步都能回答“上一层解决了什么，又留下什么问题”。</p><h2 id="机制解释" tabindex="-1">机制解释 <a class="header-anchor" href="#机制解释" aria-label="Permalink to &quot;机制解释&quot;">​</a></h2><h3 id="第一阶段-postgresql-与-sql-分析" tabindex="-1">第一阶段：PostgreSQL 与 SQL 分析 <a class="header-anchor" href="#第一阶段-postgresql-与-sql-分析" aria-label="Permalink to &quot;第一阶段：PostgreSQL 与 SQL 分析&quot;">​</a></h3><p>目标：</p><ul><li>理解表、行、列、主键、外键、约束、事务、索引。</li><li>掌握基础查询、聚合、JOIN、CTE、窗口函数和指标 SQL。</li></ul><p>这一阶段不要急着学 Spark 或 Flink。</p><p>如果不会用 SQL 准确表达业务问题，进入大数据系统后只会把复杂度放大。</p><h3 id="第二阶段-postgresql-大表与边界" tabindex="-1">第二阶段：PostgreSQL 大表与边界 <a class="header-anchor" href="#第二阶段-postgresql-大表与边界" aria-label="Permalink to &quot;第二阶段：PostgreSQL 大表与边界&quot;">​</a></h3><p>目标：</p><ul><li>理解大表为什么慢。</li><li>学会分区、索引、物化视图、执行计划。</li><li>能判断业务库分析边界。</li></ul><p>这一阶段训练的是系统压力判断。</p><p>你要知道什么时候加索引，什么时候做预计算，什么时候应该把分析迁出去。</p><h3 id="第三阶段-数仓建模" tabindex="-1">第三阶段：数仓建模 <a class="header-anchor" href="#第三阶段-数仓建模" aria-label="Permalink to &quot;第三阶段：数仓建模&quot;">​</a></h3><p>目标：</p><ul><li>理解 ODS / DWD / DWS / ADS。</li><li>设计事实表和维度表。</li><li>定义指标口径。</li><li>管理粒度和血缘。</li></ul><p>这一阶段从“查表”进入“建模”。</p><h3 id="第四阶段-etl-cdc" tabindex="-1">第四阶段：ETL / CDC <a class="header-anchor" href="#第四阶段-etl-cdc" aria-label="Permalink to &quot;第四阶段：ETL / CDC&quot;">​</a></h3><p>目标：</p><ul><li>理解数据如何从 PostgreSQL 进入数仓。</li><li>区分 ETL / ELT。</li><li>理解 CDC、WAL、Debezium、Kafka Connect。</li><li>能设计批量和实时同步链路。</li></ul><p>这一阶段从“模型设计”进入“工程链路”。</p><h3 id="第五阶段-olap-与批处理" tabindex="-1">第五阶段：OLAP 与批处理 <a class="header-anchor" href="#第五阶段-olap-与批处理" aria-label="Permalink to &quot;第五阶段：OLAP 与批处理&quot;">​</a></h3><p>目标：</p><ul><li>理解 ClickHouse / Doris / DuckDB。</li><li>理解 Hive / Spark / Trino。</li><li>理解列式存储、Shuffle、Parquet、ORC、MPP。</li></ul><p>这一阶段学习如何处理历史数据和高性能分析。</p><h3 id="第六阶段-实时数据" tabindex="-1">第六阶段：实时数据 <a class="header-anchor" href="#第六阶段-实时数据" aria-label="Permalink to &quot;第六阶段：实时数据&quot;">​</a></h3><p>目标：</p><ul><li>理解 Kafka 事件流模型。</li><li>理解 Flink 状态计算。</li><li>掌握 Event Time、Watermark、Window、Checkpoint。</li></ul><p>这一阶段学习如何回答“正在发生什么”。</p><h3 id="第七阶段-向量数据库" tabindex="-1">第七阶段：向量数据库 <a class="header-anchor" href="#第七阶段-向量数据库" aria-label="Permalink to &quot;第七阶段：向量数据库&quot;">​</a></h3><p>目标：</p><ul><li>理解 Embedding。</li><li>理解 Chunking。</li><li>理解 Vector Search。</li><li>掌握 pgvector、Milvus / Qdrant 的边界。</li><li>理解 Hybrid Search 和 RAG。</li></ul><p>这一阶段把非结构化数据接入 AI 应用。</p><h3 id="第八阶段-图数据库" tabindex="-1">第八阶段：图数据库 <a class="header-anchor" href="#第八阶段-图数据库" aria-label="Permalink to &quot;第八阶段：图数据库&quot;">​</a></h3><p>目标：</p><ul><li>理解图模型。</li><li>学会 Cypher 基础。</li><li>理解 Neo4j / NebulaGraph。</li><li>理解知识图谱、图算法和 GraphRAG。</li></ul><p>这一阶段把关系网络纳入数据系统。</p><h3 id="第九阶段-数据湖-湖仓" tabindex="-1">第九阶段：数据湖 / 湖仓 <a class="header-anchor" href="#第九阶段-数据湖-湖仓" aria-label="Permalink to &quot;第九阶段：数据湖 / 湖仓&quot;">​</a></h3><p>目标：</p><ul><li>理解对象存储。</li><li>理解 Parquet。</li><li>理解 Iceberg / Delta / Hudi。</li><li>理解 Catalog 和多引擎查询。</li></ul><p>这一阶段建立开放存储和现代分析底座。</p><h3 id="第十阶段-数据治理" tabindex="-1">第十阶段：数据治理 <a class="header-anchor" href="#第十阶段-数据治理" aria-label="Permalink to &quot;第十阶段：数据治理&quot;">​</a></h3><p>目标：</p><ul><li>理解元数据。</li><li>理解数据质量。</li><li>理解数据血缘。</li><li>理解指标治理。</li><li>理解向量和图数据治理。</li><li>理解权限安全、调度运维和成本优化。</li></ul><p>这一阶段让数据系统从“能跑”变成“可信、可管、可复用”。</p><h2 id="系统位置" tabindex="-1">系统位置 <a class="header-anchor" href="#系统位置" aria-label="Permalink to &quot;系统位置&quot;">​</a></h2><p>本章是全书的学习路线控制面。第 1-14 章回答“每一类系统是什么、为什么出现、如何落地”，本章回答“读者应该按什么顺序掌握这些能力”。</p><p>它也为第 16 章能力地图做准备：学习顺序描述路径，能力地图描述最终应形成的能力结构。</p><h2 id="场景案例" tabindex="-1">场景案例 <a class="header-anchor" href="#场景案例" aria-label="Permalink to &quot;场景案例&quot;">​</a></h2><p>如果读者当前只会写基础 SQL，推荐路线是：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>先完成 PostgreSQL 电商分析库</span></span>
<span class="line"><span>  -&gt; 再做 PostgreSQL 到 ClickHouse</span></span>
<span class="line"><span>  -&gt; 再做 CDC 实时订单看板</span></span>
<span class="line"><span>  -&gt; 再做 Mini Lakehouse</span></span>
<span class="line"><span>  -&gt; 最后做 RAG、GraphRAG 和治理平台</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><p>如果读者已经做过数仓，但对 AI 数据系统不熟，推荐从第 10 章开始补向量、图和知识治理，但仍要回头确认第 5、6、13 章的建模、链路和治理能力是否扎实。</p><h2 id="常见误区" tabindex="-1">常见误区 <a class="header-anchor" href="#常见误区" aria-label="Permalink to &quot;常见误区&quot;">​</a></h2><p><strong>误区一：先学最火的工具。</strong></p><p>工具热度不等于学习顺序。没有 SQL、建模和链路基础，直接学 Spark、Flink 或向量数据库，很容易只会跑 Demo。</p><p><strong>误区二：学完 PostgreSQL 就停下。</strong></p><p>PostgreSQL 是入口，不是终点。它帮助建立数据库直觉，但大规模分析、实时处理、湖仓、AI 检索和治理还需要继续迁移。</p><p><strong>误区三：AI 数据系统可以跳过数仓和治理。</strong></p><p>RAG 和 GraphRAG 仍然需要数据来源、权限、版本、评测和质量控制。AI 只会放大数据基础的好坏。</p><h2 id="实战任务" tabindex="-1">实战任务 <a class="header-anchor" href="#实战任务" aria-label="Permalink to &quot;实战任务&quot;">​</a></h2><p>给自己写一份 30 天学习计划：</p><ul><li>第 1 周：PostgreSQL、SQL、指标口径。</li><li>第 2 周：大表、OLTP/OLAP、数仓建模。</li><li>第 3 周：ETL/CDC、批处理、实时处理、OLAP。</li><li>第 4 周：湖仓、向量、图、治理和项目复盘。</li></ul><p>每周至少交付一个可检查产物：SQL 文件、建模文档、链路设计、架构图、评测表或治理清单。</p><h2 id="小结引出下一章" tabindex="-1">小结引出下一章 <a class="header-anchor" href="#小结引出下一章" aria-label="Permalink to &quot;小结引出下一章&quot;">​</a></h2><p>推荐路线是：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>PostgreSQL</span></span>
<span class="line"><span>  -&gt; SQL</span></span>
<span class="line"><span>  -&gt; 大表边界</span></span>
<span class="line"><span>  -&gt; 数仓</span></span>
<span class="line"><span>  -&gt; ETL / CDC</span></span>
<span class="line"><span>  -&gt; 批处理 / OLAP</span></span>
<span class="line"><span>  -&gt; 实时计算</span></span>
<span class="line"><span>  -&gt; 向量</span></span>
<span class="line"><span>  -&gt; 图</span></span>
<span class="line"><span>  -&gt; 湖仓</span></span>
<span class="line"><span>  -&gt; 治理</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br></div></div><p>这条路线的优势是每一步都能解释下一步为什么出现。</p><p>下一章进入能力地图，把这条路线沉淀成可检查的能力结构。</p>`,75))])}const L=s(c,[["render",h]]);export{k as __pageData,L as default};
